// Parse milestone submitted event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'milestone.submitted',
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    creatorId: d.creatorId,
    marketplaceId: d.marketplaceId,
    deliverableHash: d.deliverableHash,
    amount: d.amount,
    currency: d.currency,
    timestamp: payload.timestamp
  }
}];

// Parse milestone approved event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'milestone.approved',
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    creatorId: d.creatorId,
    marketplaceId: d.marketplaceId,
    amount: d.amount,
    currency: d.currency,
    timestamp: payload.timestamp
  }
}];

// Parse milestone released event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'milestone.released',
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    creatorId: d.creatorId,
    marketplaceId: d.marketplaceId,
    amount: d.amount,
    currency: d.currency,
    txHash: d.txHash,
    platformFee: d.platformFee,
    mccTokenId: d.mccTokenId,
    timestamp: payload.timestamp
  }
}];

// Parse contract completed event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'contract.completed',
    contractId: d.contractId,
    creatorId: d.creatorId,
    marketplaceId: d.marketplaceId,
    totalAmount: d.totalAmount,
    currency: d.currency,
    milestonesCompleted: d.milestonesCompleted,
    timestamp: payload.timestamp
  }
}];

// Notify marketplace: deliverable submitted, ready for review
const data = $input.first().json;

console.log(`[StudioLedger] NOTIFY MARKETPLACE: Milestone ${data.milestoneSeq} submitted for contract ${data.contractId}`);
console.log(`[StudioLedger] Deliverable hash: ${data.deliverableHash}`);
console.log(`[StudioLedger] Action required: Review and approve/reject`);

return [{
  json: {
    ...data,
    notification: 'marketplace_review_needed',
    message: `Milestone ${data.milestoneSeq} submitted — awaiting your review`
  }
}];

// Notify creator: milestone approved, payment incoming
const data = $input.first().json;

console.log(`[StudioLedger] NOTIFY CREATOR: Milestone ${data.milestoneSeq} approved for contract ${data.contractId}`);
console.log(`[StudioLedger] Payment of ${data.amount} ${data.currency} incoming`);

return [{
  json: {
    ...data,
    notification: 'creator_payment_incoming',
    message: `Milestone ${data.milestoneSeq} approved — ${data.amount} ${data.currency} payment incoming`
  }
}];

// Notify both parties: funds released + MCC minted
const data = $input.first().json;

console.log(`[StudioLedger] FUNDS RELEASED: ${data.amount} ${data.currency} for milestone ${data.milestoneSeq}`);
console.log(`[StudioLedger] TX Hash: ${data.txHash}`);
console.log(`[StudioLedger] Platform fee: ${data.platformFee}`);
if (data.mccTokenId) {
  console.log(`[StudioLedger] MCC minted: ${data.mccTokenId}`);
}

return [{
  json: {
    ...data,
    notification: 'funds_released',
    message: `${data.amount} ${data.currency} released — MCC credential issued`
  }
}];

// Contract fully completed — celebrate!
const data = $input.first().json;

console.log(`[StudioLedger] CONTRACT COMPLETED: ${data.contractId}`);
console.log(`[StudioLedger] Total: ${data.totalAmount} ${data.currency}`);
console.log(`[StudioLedger] Milestones: ${data.milestonesCompleted}`);

return [{
  json: {
    ...data,
    notification: 'contract_completed',
    message: `Contract ${data.contractId} completed — all milestones delivered!`
  }
}];
